| caption1= {{{logo_caption|}}}
| image2  = {{#invoke:InfoboxImage|InfoboxImage|image={{{image|}}}|size={{{image_size|}}}|alt={{{image_alt|}}}|sizedefault=frameless}}
| caption2= {{{caption|}}}
| label1  = Type
