| data13  = {{{og|}}}
| label14 = [[Gravity (alcoholic beverage)|Final gravity]]
| data14  = {{{fg|}}}
| label15 = [[International Bitterness Units scale|IBU scale]]
| data15  = {{{ibu|}}}
